const triggerData = $('Trigger sub-workflow agente').first().json;
const filas = $input.all().map(i => i.json);

const MAX_TOKENS = 6000;
let tokensAcum = 0;
const historialFiltrado = [];

for (const fila of filas) {
  const tokens = fila.tokens_aprox || Math.ceil((fila.contenido || '').length / 4);
  if (tokensAcum + tokens > MAX_TOKENS && fila.turno !== Math.min(...filas.map(f => f.turno))) break;
  tokensAcum += tokens;
  historialFiltrado.push(fila);
}

const historialOrdenado = historialFiltrado.reverse();
const messages = historialOrdenado.map(h => ({
  role: h.rol,
  content: h.contenido
}));

return [{
  json: {
    historial: messages,
    turno_maximo: filas.length > 0 ? Math.max(...filas.map(f => f.turno)) : 0,
    tokens_acumulados: tokensAcum
  }
}];

const triggerData = $('Trigger sub-workflow agente').first().json;
const historialData = $('Reconstruir historial y verificar límite de tokens').first().json;
const sessionData = $input.first().json || {};

const msgTexto = (triggerData.mensaje_texto || '').trim();
const PATRONES_CONFIRMAR = ['CONFIRMAR', 'CONFIRMAR ELIMINAR', 'CONFIRMAR MASIVO'];
const PATRONES_CANCELAR = ['cancelar', 'no', 'no confirmar', 'cancela'];

const hayPendiente = !!sessionData.datos_pendientes && sessionData.estado === 'pendiente_confirmacion';
const expirado = sessionData.expira && new Date(sessionData.expira) < new Date();
const esConfirmacion = PATRONES_CONFIRMAR.includes(msgTexto.toUpperCase());
const esCancelacion = PATRONES_CANCELAR.includes(msgTexto.toLowerCase());
const esReseteo = ['nueva consulta', 'reiniciar', 'restart'].includes(msgTexto.toLowerCase());

let flujo;
if (triggerData.imagen_error) {
  flujo = 'agente_normal';
} else if (hayPendiente && !expirado && esConfirmacion) {
  flujo = 'ejecutar_confirmacion';
} else if (hayPendiente && !expirado && esCancelacion) {
  flujo = 'cancelar_confirmacion';
} else if (hayPendiente && expirado) {
  flujo = 'confirmacion_expirada';
} else if (esReseteo) {
  flujo = 'resetear_sesion';
} else {
  flujo = 'agente_normal';
}

const datosParaAgente = {
  ...triggerData,
  historial: historialData.historial || [],
  turno_maximo: historialData.turno_maximo || 0,
  session_estado: sessionData.estado || 'idle',
  datos_pendientes: sessionData.datos_pendientes || null,
  flujo,
  mensaje_para_agente: triggerData.imagen_error || msgTexto
};

return [{ json: datosParaAgente }];

const datos = $input.first().json;

let contenidoMensaje = datos.mensaje_para_agente || '';

if (datos.tipo_mensaje === 'imagen' && datos.imagen_base64) {
  contenidoMensaje = JSON.stringify({
    tipo: 'imagen_con_texto',
    texto: datos.mensaje_para_agente || '',
    imagen_base64: datos.imagen_base64,
    imagen_mimetype: datos.imagen_mimetype
  });
}

if (datos.datos_pendientes) {
  contenidoMensaje += '\n\n[CONTEXTO SISTEMA: Hay una acción pendiente de confirmación. ' +
    'El usuario puede responder CONFIRMAR para ejecutarla o CANCELAR para descartarla. ' +
    'Acción pendiente: ' + JSON.stringify(datos.datos_pendientes) + ']';
}

const systemPromptBase = `Eres el asistente de gestión de catálogo para esta empresa.\nROL DEL USUARIO: ${datos.rol}\nCLIENTE ID: ${datos.cliente_id}\nSCHEMA BD: ${datos.schema}\nECOMMERCE: ${datos.ecommerce_tipo}\nCREDENCIAL N8N: ${datos.n8n_credential_name}\nCARPETA CLOUDINARY: ${datos.cloudinary_folder}\nINSTANCIA WHATSAPP: ${datos.whatsapp_instance}\nSERVER URL: ${datos.server_url}\nTELÉFONO USUARIO: ${datos.telefono}`;

return [{
  json: {
    ...datos,
    mensaje_construido: contenidoMensaje,
    system_prompt_contexto: systemPromptBase
  }
}];

const inputData = $input.first().json;
const triggerData = $('Trigger sub-workflow agente').first().json;

let respuesta;
let nuevoEstado = 'idle';
let datosPendientes = null;

if (inputData.output !== undefined) {
  respuesta = String(inputData.output);
} else if (inputData.respuesta_agente !== undefined) {
  respuesta = inputData.respuesta_agente;
} else {
  respuesta = 'Ocurrió un error inesperado. Ya fue registrado y el administrador fue notificado.';
}

if (respuesta.includes('CONFIRMAR') || respuesta.includes('Confirmas')) {
  nuevoEstado = 'pendiente_confirmacion';
}

const MAX_CHARS = 4000;
let respuestaFinal = respuesta;
if (respuesta.length > MAX_CHARS) {
  respuestaFinal = respuesta.substring(0, MAX_CHARS - 50) +
    '...\n\n_Respuesta truncada. Escribe "continuar" para ver más._';
}

return [{
  json: {
    ...triggerData,
    respuesta_final: respuestaFinal,
    respuesta_completa: respuesta,
    nuevo_estado_sesion: nuevoEstado,
    datos_pendientes_nuevos: datosPendientes
  }
}];

const errorData = $input.first().json;
const triggerData = $('Trigger sub-workflow agente').first().json;

return [{
  json: {
    schema: triggerData.schema,
    telefono: triggerData.telefono,
    whatsapp_instance: triggerData.whatsapp_instance,
    server_url: triggerData.server_url,
    mensaje_error: 'Ocurrió un error inesperado. Ya fue registrado y el administrador fue notificado.',
    error_detalle: errorData.error?.message || JSON.stringify(errorData.error || {}),
    nodo_fallido: errorData.execution?.lastNodeExecuted || 'desconocido'
  }
}];
